mapper.select:
SELECT s.ID, s.SCRAP_CODE, s.TITLE, s.USE_COMPANY_ID, s.USE_ORG_ID, s.APPLY_USER, s.APPLY_REASON, s.EXECUTE_USER, s.EXECUTE_FULFIL_TIME, s.STATUS, s.DEL_FLAG, s.CREATE_BY, s.CREATE_BY_NAME, s.CREATE_TIME, s.UPDATE_BY, s.UPDATE_BY_NAME, s.UPDATE_TIME, s.FLOW_ID, d.DEPT_NAME as USE_COMPANY_NAME, u.DEPT_NAME as USE_ORG_NAME, su.USER_NAME as APPLY_USER_NAME, CASE s.STATUS WHEN 1 THEN '审批中' WHEN 2 THEN '审批成功' WHEN 3 THEN '审批未通过' ELSE '未知' END as STATUS_NAME FROM E_M_EQUIP_SCRAP s LEFT JOIN SYS_DEPT d ON s.USE_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON s.USE_ORG_ID = u.ID LEFT JOIN SYS_USER su ON s.APPLY_USER = su.ID AND su.STATUS != 0
s.DEL_FLAG = 0
AND s.TITLE LIKE #{titlePattern}
AND s.USE_COMPANY_ID = #{useCompanyId}
AND s.USE_ORG_ID = #{useOrgId}
AND s.STATUS = #{status}
AND s.SCRAP_CODE LIKE #{scrapCodePattern}
ORDER BY s.CREATE_TIME DESC

SELECT s.ID, s.SCRAP_CODE, s.TITLE, s.USE_COMPANY_ID, s.USE_ORG_ID, s.APPLY_USER, s.APPLY_REASON, s.EXECUTE_USER, s.EXECUTE_FULFIL_TIME, s.STATUS, s.DEL_FLAG, s.CREATE_BY, s.CREATE_BY_NAME, s.CREATE_TIME, s.UPDATE_BY, s.UPDATE_BY_NAME, s.UPDATE_TIME, s.FLOW_ID, d.DEPT_NAME as USE_COMPANY_NAME, u.DEPT_NAME as USE_ORG_NAME, su.USER_NAME as APPLY_USER_NAME, CASE s.STATUS WHEN 1 THEN '审批中' WHEN 2 THEN '审批成功' WHEN 3 THEN '审批未通过' ELSE '未知' END as STATUS_NAME FROM E_M_EQUIP_SCRAP s LEFT JOIN SYS_DEPT d ON s.USE_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON s.USE_ORG_ID = u.ID LEFT JOIN SYS_USER su ON s.APPLY_USER = su.ID AND su.STATUS != 0
s.DEL_FLAG = 0
AND s.SCRAP_CODE LIKE #{scrapCodePattern}
AND s.TITLE LIKE #{titlePattern}
AND s.USE_COMPANY_ID = #{useCompanyId}
AND s.USE_ORG_ID = #{useOrgId}
AND s.STATUS = #{status}
ORDER BY s.CREATE_TIME DESC

