UPDATE E_M_EQUIP_SCRAP
SCRAP_CODE = #{scrapCode}, TITLE = #{title}, USE_COMPANY_ID = #{useCompanyId}, USE_ORG_ID = #{useOrgId}, APPLY_USER = #{applyUser}, APPLY_REASON = #{applyReason}, STATUS = #{status}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime}, FLOW_ID = #{flowId}
