UPDATE E_M_EQUIP_SCRAP
STATUS = #{status}, EXECUTE_USER = #{executeUser}, EXECUTE_FULFIL_TIME = #{executeFulfilTime}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime}
WHERE ID = #{id}

mapper.select:
SELECT e.ID as equipId, e.EQUIP_CODE as equipCode, e.EQUIP_NAME as equipName, e.SPECIFIC_CODE as equipSpecification, e.MODEL_NUMBER as modelNumber, e.EQUIP_BIG_CATEGORY_NAME as equipBigCategoryName, e.EQUIP_MIDDLE_CATEGORY_NAME as equipMiddleCategoryName, e.EQUIP_SMALL_CATEGORY_NAME as equipSmallCategoryName,
u.DEPT_NAME as useOrgName, u.ID as useOrgId, (SELECT ID FROM SYS_DEPT WHERE ID = u.PARENT_ID) as useCompanyId, (SELECT DEPT_NAME FROM SYS_DEPT WHERE ID = u.PARENT_ID) as useCompanyName, e.EQUIP_STATE as equipState, e.EQUIP_STATE_NAME as equipStateName, f.PRICE as price, f.NET_VALUE as netValue FROM E_M_EQPT_INFO e LEFT JOIN E_M_EQPT_FINANCE f ON e.ID = f.EQUIP_ID LEFT JOIN SYS_DEPT d ON e.USE_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON e.USE_ORG_ID = u.ID
e.DEL_FLAG = 0 AND e.EQUIP_STATE != '04'
AND e.EQUIP_BIG_CATEGORY_ID = #{equipBigCategoryId}
AND e.EQUIP_MIDDLE_CATEGORY_ID = #{equipMiddleCategoryId}
AND e.EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND e.EQUIP_CODE LIKE #{equipCodePattern}
AND e.USE_COMPANY_ID = #{useCompanyId}
AND e.USE_ORG_ID = #{useOrgId}
AND NOT EXISTS ( SELECT 1 FROM E_M_EQUIP_SCRAP_HISTORY h INNER JOIN E_M_EQUIP_SCRAP s ON h.ORDER_ID = s.ID WHERE h.EQUIP_ID = e.ID AND h.DEL_FLAG = 0 AND s.DEL_FLAG = 0 AND s.STATUS = 1 )
ORDER BY e.CREATE_TIME DESC
